import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../AuthContext"; // từ components ra src

export default function Login() {
    const { login } = useAuth();
    const nav = useNavigate();
    const [f, setF] = useState({ username: "", password: "" });
    const [err, setErr] = useState("");

    const submit = async (e) => {
        e.preventDefault();
        setErr("");
        try { await login(f.username, f.password); nav("/"); }
        catch { setErr("Đăng nhập thất bại"); }
    };

    return (
        <form onSubmit={submit} style={{ maxWidth: 360, margin: "80px auto" }}>
            <h2>Đăng nhập</h2>
            <input value={f.username} onChange={e=>setF({...f, username:e.target.value})} placeholder="Username"/>
            <input type="password" value={f.password} onChange={e=>setF({...f, password:e.target.value})}
                   placeholder="Password" style={{ display:"block", marginTop:8 }}/>
            {err && <p style={{color:"red"}}>{err}</p>}
            <button style={{ marginTop: 8 }}>Login</button>
        </form>
    );
}
